:root {
	--color-black: #1B1D25;
	--color-white: #FFFFFF;

	--color-gray: #BEC5D3;
	--color-gray-second: #5C6474;
	--color-gray-blue: #97A2B8;
	--color-gray-light: #D9D9D9;
	--color-dark-card-background: linear-gradient(180deg, #20232D 0%, #2C2D3C 100%);

	--color-cyan: #6BEAF9;
	--color-blue: #4F95FF;
	--color-red: #FF6C56;
	--color-green: #7DDE8E;

	--color-black-bg: #17171B;
	--color-gray-bg: #F9F9F9;
	--color-light-card-bg: #F7F7F74D;
	--color-header-footer-bg: #4D4F6833;

	--color-light-gray-stroke: linear-gradient(179.96deg, #E0E8F4 0.03%, #D1D6DD 102.68%);
	--color-dark-gray-stroke: linear-gradient(180deg, #454F6B 0%, #2F2F40 100%);
	--color-ecosystem-gradient: linear-gradient(180deg, #171B3B 0%, #17171B 52.21%);

	--font-family: "Vela Sans", sans-serif;

	--border-radius: 6.25rem;

    --backdrop-blur-header: 1.25rem;    
    --backdrop-blur-table: 2.5rem;     
    --backdrop-blur-ecosystem: 5rem;

	--container-width: 105rem;
	--container-padding-x: 1.875rem;

	--header-height: 4.6875rem;

	--transition-duration: 0.4s;
}

/* ─── DARK (default) ─────────────────────────── */
:root[data-theme="dark"] {
	--color-bg: var(--color-black-bg);
	--color-bg-invert: var(--color-white);
	--color-text: var(--color-gray-light);
	--color-heading: var(--color-white);
	--color-link: var(--color-white);
	--color-link-hover: var(--color-gray);

	--header-bg: var(--color-header-footer-bg);

	--card-bg: var(--color-dark-card-background);
	--card-border: var(--color-dark-gray-stroke);
    --locale-selector-bg: #20232D;

	--button-primary-bg: transparent;
	--button-primary-color: var(--color-white);

	--button-secondary-bg: transparent;
	--button-secondary-color: var(--color-gray-second);
	--button-secondary-border: var(--color-gray-second);

	--button-burger-button-bg: var(--color-white);

	--input-bg: var(--color-header-footer-bg);
}

/* ─── LIGHT ──────────────────────────────────── */
:root[data-theme="light"] {
	--color-bg: var(--color-white);
	--color-bg-invert: var(--color-black-bg);
	--color-text: var(--color-gray-second);
	--color-heading: var(--color-black);
	--color-link: var(--color-black);
	--color-link-hover: var(--color-gray-second);

	--header-bg: var(--color-light-card-bg);

	--card-bg: var(--color-gray-bg);
	--card-border: var(--color-light-gray-stroke);
    --locale-selector-bg: var(--color-gray-bg);

	--button-primary-bg: transparent;
	--button-primary-color: var(--color-black);

	--button-secondary-bg: transparent;
	--button-secondary-color: var(--color-black);
	--button-secondary-border: var(--color-black);

	--button-burger-button-bg: var(--color-black);

	--input-bg: var(--color-white);
}

::view-transition-old(root),
::view-transition-new(root) {
  animation: none;
  mix-blend-mode: normal;

  /* animation-duration: var(--transition-duration); */
}

body {
	font-family: var(--font-family);
	color: var(--color-text);
	font-weight: 400;
	font-size: 1rem;
	line-height: 1.35;
	letter-spacing: -0.01em;
	background-color: var(--color-bg);
}

h2,
h3,
h4,
h5,
h6 {
	color: var(--color-heading);
	font-weight: 700;
}

h1 {
	color: var(--color-heading);
	font-weight: 500;
	font-size: clamp(1.875rem, 4.16vw, 5rem);
	line-height: 1.05;
}

h2 {
	font-size: 3.125rem;
	line-height: 1.2;
}

a {
	color: var(--color-link);
	text-decoration: none;
}

svg :is(path, circle, rect, ellipse, line, polyline, polygon) {
  transition: fill var(--transition-duration) ease,
              stroke var(--transition-duration) ease;
}

/* ─── Checkbox ───────────────────────────────── */
.checkbox-item {
	display: -webkit-box;
	display: -ms-flexbox;
	display: flex;
	-webkit-box-align: center;
	-ms-flex-align: center;
	align-items: center;
	gap: 0.625rem;
	cursor: pointer;
	position: relative;
}

.checkbox-item input[type="checkbox"] {
	position: absolute;
	opacity: 0;
	cursor: pointer;
}

.checkbox-custom {
	position: relative;
	width: 1.25rem;
	aspect-ratio: 1;
	border-radius: 50%;
	background: var(--color-bg);
	-ms-flex-negative: 0;
	flex-shrink: 0;
}

.checkbox-custom::before {
	content: "";
	position: absolute;
	inset: 0;
	padding: 0.125rem;
	border-radius: 50%;
	background: var(--card-border);
	-webkit-mask: 
      linear-gradient(#000 0 0) content-box, 
      linear-gradient(#000 0 0);
	-webkit-mask-composite: xor;
	mask-composite: exclude;
	pointer-events: none;
}

.checkbox-item input[type="checkbox"]:checked+.checkbox-custom::after {
	content: "";
	position: absolute;
	left: 50%;
	top: 50%;
	-webkit-transform: translate(-50%, -50%);
	-ms-transform: translate(-50%, -50%);
	transform: translate(-50%, -50%);
	width: 1rem;
	aspect-ratio: 1;
	background-image: url('/core/image/${CHECBOX_DOT@IMAGE}/get');
	background-repeat: no-repeat;
	background-size: contain;
	background-position: center;
}

.checkbox-label {
	color: var(--color-text);
	font-size: 1rem;
	font-weight: 400;
	line-height: 135%;
}

.checkbox-label .underline {
	text-decoration: underline;
}

.checkbox-item:hover .checkbox-custom {
	border-color: #6bedfa;
}

/* ─── Input ──────────────────────────────────── */
.input {
	background: var(--input-bg);
	border-radius: 1.25rem;
	color: var(--color-heading);
	font-weight: 400;
	line-height: 135%;
	height: 4.5rem;
	padding: 1.5625rem 2.1875rem;
	font-size: 1.25rem;
	border: none;
}

/* ─── Button ─────────────────────────────────── */
.button {
	display: -webkit-inline-box;
	display: -ms-inline-flexbox;
	display: inline-flex;
	-webkit-box-align: center;
	-ms-flex-align: center;
	align-items: center;
	-webkit-box-pack: center;
	-ms-flex-pack: center;
	justify-content: center;
	min-width: 13.8125rem;
	padding: 1.0625rem 1.625rem;
	border: none;
	border-radius: var(--border-radius);
	font-weight: 500;
	font-size: 1.25rem;
	line-height: 1.3;
	letter-spacing: 0%;
	white-space: nowrap;
    transition: box-shadow var(--transition-duration) ease;
}

.button:hover {
	box-shadow: 0px 0px 32.2px 0px var(--color-cyan);
}

.button::before {
  transition: background var(--transition-duration) ease;
}


.button::after {
	content: "";
	position: absolute;
	bottom: 0;
	left: 50%;
	-webkit-transform: translateX(-50%);
	-ms-transform: translateX(-50%);
	transform: translateX(-50%);
	width: 100%;
	height: 100%;
	background-image: var(--button-bg, none);
	background-repeat: no-repeat;
	background-position: center bottom;
	background-size: contain;
	opacity: 0;
	pointer-events: none;
	z-index: 1;
}

.button:hover::after {
	opacity: 1;
}

.button-primary {
	position: relative;
	background-color: var(--button-primary-bg);
	color: var(--button-primary-color);
}

.button-primary::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: var(--border-radius);
  padding: 0.125rem; /* Frame width */

  /* Frame gradient */
  background: linear-gradient(249.99deg,
      rgba(107, 237, 249, 0) 4.98%,
      #6bedf9 37.35%,
      #ffa72c 72.51%,
      rgba(239, 92, 255, 0) 96.41%);

  /* Using black for mask - this is a standard */
  /* Using two layers: first for the content, another for the rest */
  -webkit-mask: 
    linear-gradient(#000 0 0) content-box, 
    linear-gradient(#000 0 0);

  /* Most importan part for mobile Safari/Chrome */
  -webkit-mask-composite: xor; 
  mask-composite: exclude;

  pointer-events: none;
  z-index: 1;
}

.button-primary:hover::before {
	background: linear-gradient(264.85deg,
			rgba(239, 92, 255, 0) -6.54%,
			#ffa72c 24.73%,
			#6bedf9 70.73%,
			rgba(107, 237, 249, 0) 113.1%);
}

.button:hover .button-icon {
	-webkit-transform: rotate(180deg);
	-ms-transform: rotate(180deg);
	transform: rotate(180deg);
}

.button .button-icon {
  transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.button-icon {
	color: var(--button-primary-color);
	-ms-flex-negative: 0;
	flex-shrink: 0;
	width: 1.3125rem;
	aspect-ratio: 1;
	-webkit-transition: -webkit-transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
	transition: -webkit-transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
	-o-transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
	transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
	transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1), -webkit-transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

[dir="ltr"] .button-icon {
    margin-right: 0.5rem;
}

[dir="rtl"] .button-icon {
	margin-left: 0.5rem;
}

.button-secondary {
	display: -webkit-inline-box;
	display: -ms-inline-flexbox;
	display: inline-flex;
	-webkit-box-align: center;
	-ms-flex-align: center;
	align-items: center;
	-webkit-box-pack: center;
	-ms-flex-pack: center;
	justify-content: center;
	padding: 1.0625rem 1.625rem;
	height: 3.75rem;
	border: none;
	border-radius: var(--border-radius);
	font-weight: 500;
	font-size: 1.25rem;
	line-height: 1.3;
	letter-spacing: 0%;
	white-space: nowrap;
	position: relative;
	background-color: transparent;
	color: var(--color-gray-second);
	border: 1px solid var(--color-gray-second);
}

/* ─── Layout ─────────────────────────────────── */
.container {
	max-width: calc(var(--container-width) + var(--container-padding-x) * 2);
	margin-inline: auto;
	padding-inline: var(--container-padding-x);
}

.sr-only {
	clip: rect(0 0 0 0);
	-webkit-clip-path: inset(50%);
	clip-path: inset(50%);
	height: 1px;
	overflow: hidden;
	position: absolute;
	white-space: nowrap;
	width: 1px;
}

.subtitle {
	font-weight: 500;
	font-size: 1.5625rem;
	/* color: var(--color-gray-second); */
    color: #A1A7B5;
	margin-top: 1.875rem;
}

body.loading {
  overflow: hidden;
  height: 100vh; 
}

#app-loader {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: var(--color-black-bg); 
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 9999;
  transition: opacity var(--transition-duration) ease, visibility 0.5s;
	overflow: hidden;
}

.loader-content {
  text-align: center;
  color: #fff;
  font-family: sans-serif;
}

.loader-svg {
   width: 64px;
  aspect-ratio: 1;
  animation: 
    pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { 
    opacity: 0.4; 
    scale: 0.95; 
  }
  50% { 
    opacity: 1; 
    scale: 1.05; 
  }
}

/* ================================================================
   MEDIA QUERIES
   Breakpoints: 120rem | 90rem | 80rem | 64rem | 48rem | 37.5rem
================================================================ */

/* ─── < 120rem ───────────────────────────────── */
@media (width < 120rem) {
	:root {
		--header-height: 4.375rem;
	}

	h1 {
		line-height: 1.07;
	}

	h2 {
		font-size: 3rem;
	}

	.button,
	.button-secondary {
		font-weight: 400;
		font-size: 1rem;
	}

	.button-secondary {
		height: 3.125rem;
	}

	.subtitle {
		font-weight: 400;
		font-size: 1.25rem;
		margin-top: 1.25rem;
	}
}

/* ─── < 80rem ────────────────────────────────── */
@media (width < 80rem) {
	:root {
		--header-height: 3.75rem;
	}
}

/* ─── < 48rem ────────────────────────────────── */
@media (width < 48rem) {
	:root {
		--header-height: 3.125rem;
	}

	h2 {
		font-size: 1.5625rem;
	}

	.input {
		height: 3.75rem;
		padding: 1.25rem;
		font-size: 0.875rem;
	}

	.container {
		padding-inline: var(--container-padding-x);
	}

	.subtitle {
		margin-top: 0.9375rem;
		font-size: 1rem;
	}
}
</style>
