  min-height: 18rem;
  margin-bottom: 3rem;
}

.use-cases-carousel {
  --use-cases-gap: 1.25rem;
  position: relative;
  display: grid;
  grid-template-columns: 3rem minmax(0, 1fr) 3rem;
  grid-template-areas:
    "prev viewport next"
    ". dots .";
  column-gap: 0.75rem;
  row-gap: 1rem;
  align-items: center;
}

.use-cases-viewport {
  grid-area: viewport;
  overflow: hidden;
  padding: 0.5rem 0 2.5rem;
}

