  will-change: transform;
  transition: transform 260ms ease;
}

.use-cases-industry {
  position: relative;
  flex: 0 0 calc((100% - (var(--use-cases-gap) * (var(--use-cases-per-page, 4) - 1))) / var(--use-cases-per-page, 4));
  min-width: 0;
}

.use-cases-nav {
  width: 3rem;
