    if (document.readyState === "loading") {
      document.addEventListener("DOMContentLoaded", callback);
    } else {
      callback();
    }
  }

  function getLocale() {
    return (
      new URLSearchParams(window.location.search).get("locale") ||
      document.documentElement.lang ||
      (navigator.language ? navigator.language.slice(0, 2) : "") ||
      "en"
    );
  }

  function getOrganization() {
    var parts = window.location.pathname.split("/").filter(Boolean);
    var pagesIndex = parts.indexOf("pages");
    return pagesIndex >= 0 ? parts[pagesIndex + 1] : "";
  }

  function pickNls(nls, locale, fallback) {
    if (!nls || typeof nls !== "object") return fallback || "";
    var exact = nls[locale];
    var language = locale && locale.indexOf("-") > 0 ? nls[locale.split("-")[0]] : null;
    var english = nls.en;
    var firstKey = Object.keys(nls)[0];
    var first = firstKey ? nls[firstKey] : null;
    var chosen = exact || language || english || first || {};
    return chosen.NAME || chosen.DESCRIPTION || fallback || "";
  }

  function pickDescription(nls, locale) {
    if (!nls || typeof nls !== "object") return "";
    var exact = nls[locale];
    var language = locale && locale.indexOf("-") > 0 ? nls[locale.split("-")[0]] : null;
    var english = nls.en;
    var firstKey = Object.keys(nls)[0];
    var first = firstKey ? nls[firstKey] : null;
    var chosen = exact || language || english || first || {};
    return chosen.DESCRIPTION || "";
  }

  function findAttributeValue(doc, code) {
    var attrs = doc && doc.attributes;
    if (!attrs || typeof attrs !== "object") return null;
    var upper = String(code).toUpperCase();

    for (var typeId in attrs) {
      if (!Object.prototype.hasOwnProperty.call(attrs, typeId)) continue;
      var group = attrs[typeId];
      if (!group || typeof group !== "object") continue;
      var entry = group[upper] || group[code] || group[code.toLowerCase()];
      if (entry && Object.prototype.hasOwnProperty.call(entry, "value")) {
        return entry.value;
      }
    }

    return null;
  }

  function normalizeIndustry(raw, locale) {
    if (Array.isArray(raw)) raw = raw[0];
    if (!raw && raw !== 0) return null;

    if (typeof raw === "object") {
      var id = raw.id || raw.code || raw.value || raw.dictionaryId || "UNKNOWN";
      var imageId =
        raw.mediaId ||
        raw.imageId ||
        (raw.image && (raw.image.id || raw.image.mediaId)) ||
        "";

      return {
        id: String(id),
        code: String(raw.code || id),
        title: pickNls(raw.nls, locale, raw.name || raw.code || String(id)),
        description: pickDescription(raw.nls, locale) || raw.description || "",
        imageId: imageId
      };
    }

    var code = String(raw).toUpperCase();
    var configured = INDUSTRIES[code];

    return {
      id: code,
      code: code,
      title: configured ? pickNls(configured.nls, locale, code) : code.replace(/[_-]+/g, " "),
      description: configured ? pickDescription(configured.nls, locale) : "",
      imageId: configured ? configured.imageId : ""
    };
  }

  function getIndustry(doc, locale) {
    var metadata = doc.metadata || {};
    return normalizeIndustry(
      findAttributeValue(doc, "INDUSTRY") ||
        metadata.INDUSTRY ||
        metadata.industry ||
        metadata.industryDictionary ||
        inferIndustryFromCode(doc && doc.code),
      locale
    );
  }

  function inferIndustryFromCode(code) {
    if (!code) return "";
    var prefix = String(code).split("_")[0].toUpperCase();
    return INDUSTRIES[prefix] ? prefix : "";
  }

  function getDocumentTitle(doc, locale) {
    return pickNls(doc.nls, locale, doc.summary || doc.code || "Untitled use case");
  }

  function fetchDocumentPage(organization, locale, documentType, offset, pageSize) {
    var url =
      "/core-cms/public/" +
      encodeURIComponent(organization) +
      "/document/list.json?locale=" +
      encodeURIComponent(locale) +
      "&type=" +
      encodeURIComponent(documentType);

    return fetch(url, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Accept: "application/json"
      },
      body: JSON.stringify({
        first: offset,
        offset: offset,
        pageSize: pageSize,
        sorting: [
          {
            field: "code",
            direction: "ASC"
          }
        ]
      })
    }).then(function (response) {
      if (!response.ok) {
        throw new Error("Use case request failed: " + response.status);
      }
      return response.json();
    });
  }

  function fetchAllDocuments(organization, locale, documentType, pageSize, maxResults) {
    var collected = [];

    function next(offset) {
      return fetchDocumentPage(organization, locale, documentType, offset, pageSize).then(function (data) {
        var result = data.result || [];
        collected = collected.concat(result);

        var total = Number(data.resultSize || data.total || result.length);
        var done =
          result.length === 0 ||
          collected.length >= total ||
          collected.length >= maxResults;

        return done ? collected.slice(0, maxResults) : next(offset + result.length);
      });
    }

    return next(0);
  }

  function groupByIndustry(docs, locale) {
    var groups = [];
    var byId = {};

    docs.forEach(function (doc) {
      var industry = getIndustry(doc, locale) || {
        id: "UNASSIGNED",
        code: "UNASSIGNED",
        title: "Other",
        description: "",
        imageId: ""
      };

      if (!byId[industry.id]) {
        byId[industry.id] = {
          industry: industry,
          docs: []
        };
        groups.push(byId[industry.id]);
      }

      byId[industry.id].docs.push(doc);
    });

    return groups;
  }

  function buildUrl(documentParam, docCode, locale) {
    var url = new URL(window.location.href);
    url.searchParams.set(documentParam, docCode);
    url.searchParams.set("locale", locale);
    return url.toString();
  }

  function renderTooltip(industry) {
    if (!industry.description) return "";
    return (
      '<span class="use-cases-tooltip" tabindex="0" aria-label="' +
      escapeHtml(industry.description) +
      '">i<span class="use-cases-tooltip-body">' +
      escapeHtml(industry.description) +
      "</span></span>"
    );
  }

  function escapeHtml(value) {
    return String(value == null ? "" : value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  function imageMarkup(industry) {
    if (!industry.imageId) {
      return '<div class="use-cases-image-fallback rounded-t-lg">Industry</div>';
    }

    return (
      '<img class="use-cases-image rounded-t-lg" src="/core/image/' +
      encodeURIComponent(industry.imageId) +
      '/get" alt="' +
      escapeHtml(industry.title) +
      '" loading="lazy">'
    );
  }

  function renderGroups(root, groups, locale) {
    var slider = root.querySelector("[data-use-cases-slider]");
    var documentParam = root.getAttribute("data-document-param") || "USE_CASE_CONTENT";
    var selectedCode = new URLSearchParams(window.location.search).get(documentParam) || "";

    var document = root.querySelector("[data-use-case-document]");
    var hasServerDocument = document && document.textContent.trim().length > 0;
    root.dataset.hasSelection = selectedCode || hasServerDocument ? "true" : "false";

    if (!groups.length) {
      slider.innerHTML = '<div class="use-cases-status text-sm text-slate-500">No use cases found.</div>';
      return;
    }

    var html =
      '<div class="use-cases-carousel" data-use-cases-carousel>' +
      '<button class="use-cases-nav use-cases-nav-prev" type="button" data-use-cases-prev aria-label="Previous industries">&lsaquo;</button>' +
      '<div class="use-cases-viewport" data-use-cases-viewport>' +
      '<div class="use-cases-industries" data-use-cases-track>';

    groups.forEach(function (group) {
      var industry = group.industry;
      var hasMore = group.docs.length > 2 ? "true" : "false";

      html +=
        '<div class="use-cases-industry" data-has-more="' +
        hasMore +
        '">' +
        '<div class="use-cases-industry-panel">' +
        imageMarkup(industry) +
        '<div class="use-cases-industry-body">' +
        '<h3 class="use-cases-industry-title">' +
        '<span>' +
        escapeHtml(industry.title) +
        "</span>" +
        renderTooltip(industry) +
        "</h3>" +
        '<div class="use-cases-list-wrap mt-2">' +
        '<div class="use-cases-list">';

      group.docs.forEach(function (doc) {
        var isActive = selectedCode && selectedCode.toUpperCase() === String(doc.code || "").toUpperCase();
        html +=
          '<a class="use-cases-link' +
          (isActive ? " is-active" : "") +
          '" href="' +
          escapeHtml(buildUrl(documentParam, doc.code, locale)) +
          '">' +
          escapeHtml(getDocumentTitle(doc, locale)) +
          "</a>";
      });

      html +=
        "</div>" +
        '<div class="use-cases-more-indicator" aria-hidden="true">...</div>' +
        "</div>" +
        "</div>" +
        "</div>" +
        "</div>";
    });

    html +=
      "</div>" +
      "</div>" +
      '<button class="use-cases-nav use-cases-nav-next" type="button" data-use-cases-next aria-label="Next industries">&rsaquo;</button>' +
      '<div class="use-cases-dots" data-use-cases-dots></div>' +
      "</div>";
    slider.innerHTML = html;
    setupSlider(slider);
  }

  function getSliderGap() {
    return 20;
  }

  function getCardsPerPage(viewport) {
    var width = viewport ? viewport.getBoundingClientRect().width : 0;
    if (width >= 1120) return 4;
    if (width >= 820) return 3;
    if (width >= 540) return 2;
    return 1;
  }

  function setupSlider(slider) {
    var carousel = slider.querySelector("[data-use-cases-carousel]");
    var viewport = slider.querySelector("[data-use-cases-viewport]");
    var track = slider.querySelector("[data-use-cases-track]");
    var previous = slider.querySelector("[data-use-cases-prev]");
    var next = slider.querySelector("[data-use-cases-next]");
    var dots = slider.querySelector("[data-use-cases-dots]");
    var cards = Array.prototype.slice.call(slider.querySelectorAll(".use-cases-industry"));
    var state = {
      page: 0,
      perPage: 1,
      pageCount: 1
    };

    if (!carousel || !viewport || !track || !cards.length) return;

    function goTo(page) {
      state.page = Math.max(0, Math.min(page, state.pageCount - 1));
      updatePosition();
    }

    function updateDots() {
      if (!dots) return;
      var html = "";
      for (var i = 0; i < state.pageCount; i += 1) {
        html +=
          '<button class="use-cases-dot' +
          (i === state.page ? " is-active" : "") +
          '" type="button" data-use-cases-page="' +
          i +
          '" aria-label="Show industry page ' +
          (i + 1) +
          '"></button>';
      }
      dots.innerHTML = html;
      dots.querySelectorAll("[data-use-cases-page]").forEach(function (dot) {
        dot.addEventListener("click", function () {
          goTo(Number(dot.getAttribute("data-use-cases-page") || 0));
        });
      });
    }

    function updatePosition() {
      var gap = getSliderGap();
      var distance = state.page * (viewport.clientWidth + gap);
      track.style.transform = "translateX(-" + distance + "px)";
      if (previous) previous.disabled = state.page === 0;
      if (next) next.disabled = state.page >= state.pageCount - 1;
      if (dots) {
        dots.querySelectorAll(".use-cases-dot").forEach(function (dot, index) {
          dot.classList.toggle("is-active", index === state.page);
        });
      }
    }

    function refresh() {
      var perPage = getCardsPerPage(viewport);
      var pageCount = Math.max(1, Math.ceil(cards.length / perPage));
      var changed = perPage !== state.perPage || pageCount !== state.pageCount;
      state.perPage = perPage;
      state.pageCount = pageCount;
      state.page = Math.min(state.page, state.pageCount - 1);
      track.style.setProperty("--use-cases-per-page", String(state.perPage));
      carousel.dataset.pages = String(state.pageCount);
      if (changed) updateDots();
      updatePosition();
    }

    if (previous) {
      previous.addEventListener("click", function () {
        goTo(state.page - 1);
      });
    }

    if (next) {
      next.addEventListener("click", function () {
        goTo(state.page + 1);
      });
    }

    window.addEventListener("resize", refresh);
    refresh();
  }

  function init(root) {
    var organization = getOrganization();
    var status = root.querySelector("[data-use-cases-status]");
    var locale = getLocale();
    var documentType = root.getAttribute("data-document-type") || "USE_CASE";
    var pageSize = Math.max(1, Number(root.getAttribute("data-page-size") || 100));
    var maxResults = Math.max(pageSize, Number(root.getAttribute("data-max-results") || 1000));

    if (!organization) {
      if (status) status.textContent = "Unable to resolve organization.";
      return;
    }

    fetchAllDocuments(organization, locale, documentType, pageSize, maxResults)
      .then(function (docs) {
        renderGroups(root, groupByIndustry(docs, locale), locale);
      })
      .catch(function (error) {
        if (status) status.textContent = "Unable to load use cases.";
        console.error(error);
      });
  }

  ready(function () {
    document.querySelectorAll("[data-use-cases]").forEach(init);
  });
})();

