    .header-button {
		display: none;
	}

    .header-burger-button {
		display: -webkit-inline-box;
		display: -ms-inline-flexbox;
		display: inline-flex;
	}

    .header-mobile-menu .locale-selector {
      display: inline-block !important;
      margin-top: 15px;
      margin-inline: auto;
    }
}

/* ─── < 64rem ────────────────────────────────── */
@media (width < 64rem) {
	.header {
		height: auto;
	}

	.header-top {
		height: var(--header-height);
	}
}

/* ─── < 37.5rem ──────────────────────────────── */
@media (width < 37.5rem) {
	.mobile-menu-button {
		max-width: 100%;
	}
}

