document.addEventListener('mouseenter', function(e) {
  if (!e.target || typeof e.target.closest !== 'function') return;
  const menuItem = e.target.closest('.header-menu-item');
  if (!menuItem || menuItem.dataset.bgLoaded) return;
  menuItem.dataset.bgLoaded = 'true';
  menuItem.style.setProperty('--menu-item-bg', 'url("/core/image/${HEADER_MENU_ITEM_SHADOW@IMAGE}/get")');
}, true);

document.addEventListener('DOMContentLoaded', function () {
  const wrapper = document.querySelector('.resources-dropdown-wrapper');
  const trigger = wrapper?.querySelector('.resources-trigger');

  if (!wrapper || !trigger) return;

  let timer;

  const openMenu = () => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      document.querySelectorAll('.is-open').forEach(el => {
        if (el !== wrapper) el.classList.remove('is-open');
      });
      wrapper.classList.add('is-open');
      trigger.setAttribute('aria-expanded', 'true');
    }, 200);
  };

  const closeMenu = () => {
    clearTimeout(timer);
    timer = setTimeout(() => {
      wrapper.classList.remove('is-open');
      trigger.setAttribute('aria-expanded', 'false');
    }, 300);
  };

  wrapper.addEventListener('mouseenter', openMenu);
  wrapper.addEventListener('mouseleave', closeMenu);

  trigger.addEventListener('click', (e) => {
    e.preventDefault();
    e.stopPropagation();
    const isOpen = wrapper.classList.contains('is-open');
    clearTimeout(timer);
    if (isOpen) {
      wrapper.classList.remove('is-open');
      trigger.setAttribute('aria-expanded', 'false');
    } else {
      wrapper.classList.add('is-open');
      trigger.setAttribute('aria-expanded', 'true');
    }
  });

  // ↓ ИЗМЕНЕНО: добавлено исключение для .locale-selector и clearTimeout
  document.addEventListener('click', (e) => {
    if (
      !wrapper.contains(e.target) &&
      !e.target.closest('.locale-selector')
    ) {
      clearTimeout(timer);
      wrapper.classList.remove('is-open');
      trigger.setAttribute('aria-expanded', 'false');
    }
  });
});

